import{_ as e,o as s,c as i,a2 as n}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Queues & Operators","description":"","frontmatter":{},"headers":[],"relativePath":"features/queues.md","filePath":"features/queues.md"}'),t={name:"features/queues.md"};function l(o,a,p,r,d,h){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="queues-operators" tabindex="-1">Queues &amp; Operators <a class="header-anchor" href="#queues-operators" aria-label="Permalink to &quot;Queues &amp; Operators&quot;">​</a></h1><p>Queues &amp; Operators provide structured call distribution for teams that answer shared inbound calls. Callers wait in a queue while Callytics connects them to available operators based on the queue setup.</p><p>Operators log in from their softphone by entering a PIN — no admin UI interaction needed to change availability. The system tracks whether operators are available, busy, or offline so you can understand staffing in real time.</p><p>Queue live state is held entirely in Redis. PostgreSQL is never polled for queue state — only Redis keys determine who is available and whether a match can be made.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Operator softphone                Caller softphone</span></span>
<span class="line"><span>      │                                 │</span></span>
<span class="line"><span>      │ dials queue_login flow          │ dials inbound DID</span></span>
<span class="line"><span>      ▼                                 ▼</span></span>
<span class="line"><span>┌─────────────┐                  ┌─────────────┐</span></span>
<span class="line"><span>│ queue_login │                  │    queue    │</span></span>
<span class="line"><span>│    node     │                  │    node     │</span></span>
<span class="line"><span>└──────┬──────┘                  └──────┬──────┘</span></span>
<span class="line"><span>       │ DTMF PIN match                 │ polls Redis every 500ms</span></span>
<span class="line"><span>       ▼                                │ queue:&lt;id&gt;:operators</span></span>
<span class="line"><span>┌─────────────────────┐                 │</span></span>
<span class="line"><span>│       Redis         │◄────────────────┘</span></span>
<span class="line"><span>│ operator:&lt;id&gt;:queue │</span></span>
<span class="line"><span>│ operator:&lt;id&gt;:chan  │────────────────► bridge created</span></span>
<span class="line"><span>│ queue:&lt;id&gt;:operators│                 mixing,dtmf_events</span></span>
<span class="line"><span>└─────────────────────┘</span></span></code></pre></div><h2 id="operator-login-flow" tabindex="-1">Operator Login Flow <a class="header-anchor" href="#operator-login-flow" aria-label="Permalink to &quot;Operator Login Flow&quot;">​</a></h2><p>Operators are created in the Operators page. Each operator can have a linked SIP extension and a hashed PIN (<code>operators.pin_hash</code>). To log into a queue, the operator calls their softphone into a flow that contains a <code>queue_login</code> node.</p><p><strong>Login sequence:</strong></p><ol><li>Operator dials into a flow containing a <code>queue_login</code> node</li><li>Stasis prompts for PIN via DTMF</li><li>Stasis matches the entered digits against <code>operators.pin_hash</code> in the database</li><li>On successful match, Stasis writes to Redis: <ul><li><code>operator:&lt;id&gt;:queue</code> = queue ID</li><li><code>operator:&lt;id&gt;:channel</code> = ARI channel ID</li><li>Adds the operator&#39;s channel to the <code>queue:&lt;id&gt;:operators</code> set</li></ul></li><li>The operator is now visible as available in the live dashboard</li><li>To log out, the operator dials <code>#</code> during the PIN prompt</li></ol><h2 id="queue-matching-flow" tabindex="-1">Queue Matching Flow <a class="header-anchor" href="#queue-matching-flow" aria-label="Permalink to &quot;Queue Matching Flow&quot;">​</a></h2><p>When a caller hits a <code>queue</code> node in a flow:</p><ol><li>Stasis checks the <code>queue:&lt;id&gt;:operators</code> set in Redis for available operator channels</li><li>If no operators are available, Stasis polls Redis every 500ms</li><li>When an operator channel appears in the set, Stasis creates a <code>mixing,dtmf_events</code> ARI bridge between the caller channel and the operator channel</li><li>Both parties are connected — the bridge type <code>mixing,dtmf_events</code> is required to prevent Asterisk from upgrading to a native RTP bridge, which would break audio through NAT after approximately 30 seconds</li><li>If the caller abandons or the timeout expires, the queue node follows the configured abandon or timeout edge</li></ol><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Operator</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Stasis</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Redis</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Caller</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Operator-&gt;&gt;Stasis: dials queue_login flow</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis-&gt;&gt;Operator: prompt for PIN (DTMF)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Operator-&gt;&gt;Stasis: enters PIN</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis-&gt;&gt;Redis: write operator state + add to queue set</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Caller-&gt;&gt;Stasis: enters queue node</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    loop poll every 500ms</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Stasis-&gt;&gt;Redis: check queue:&lt;id&gt;:operators</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Redis--&gt;&gt;Stasis: operator available</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    end</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis-&gt;&gt;Stasis: create mixing,dtmf_events bridge</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis--&gt;&gt;Caller: connected to operator</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis--&gt;&gt;Operator: connected to caller</span></span></code></pre></div><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Queue-based inbound call distribution</li><li>Operator PIN login from softphone keypresses</li><li>Real-time operator status: available, busy, or offline</li><li>Caller wait handling when no operator is free</li><li>Abandoned-call routing</li><li>Timeout routing</li><li>Live dashboard visibility for queues and operators</li></ul>`,15)])])}const g=e(t,[["render",l]]);export{u as __pageData,g as default};
